// Expande all_colabs para compatibilidade com o app.js
(function(){
  const D = window.LATAM_DATA;
  D.all_colabs = D.all_colabs.map(c=>({
    bp:c.bp, nome:c.n, email:c.e, cargo:c.ca,
    gestor:c.g, email_gestor:c.eg, area:c.ar,
    cursos:c.cr.map(cr=>({curso:cr.c,status:cr.s,vencimento_date:cr.v||'',dias_para_vencer:cr.d??null,alerta:cr.a||null}))
  }));
  D.colab_pend = D.colab_pend.map(c=>({
    bp:c.bp, nome:c.n, email:c.e, cargo:c.ca,
    gestor:c.g, email_gestor:c.eg, area:c.ar, qtd_pend:c.q,
    pendentes:c.p.map(p=>({curso:p.c,alerta:p.a,dias_para_vencer:p.d}))
  }));
})();
